fig = uifigure('Name', 'Dobot Magician Lite', 'Position', [100 100 700 600]); %[output:69c52acf]
ax = uiaxes(fig, "Position", [10 250 450 350]); %[output:69c52acf]
title(ax, "Joint Positions"); %[output:69c52acf]
xlabel(ax, 'X'); %[output:69c52acf]
ylabel(ax, 'Y'); %[output:69c52acf]
zlabel(ax, 'Z'); %[output:69c52acf]
lim = [-0.3 0.3];
ax.XLim = lim; %[output:69c52acf]
ax.YLim = lim; %[output:69c52acf]
ax.ZLim = lim; %[output:69c52acf]


origin = plot3(ax, 0, 0, 0, 'bo', MarkerFaceColor='b'); %[output:69c52acf]
hold(ax, 'on'); %[output:69c52acf]
joint2 = plot3(ax, 0.1, 0.1, 0.1, 'go', MarkerFaceColor='g'); %[output:69c52acf]
end_effector = plot3(ax, 0.2, 0.2, 0, 'ro', MarkerFaceColor='r'); %[output:69c52acf]
link2 = plot3(ax, [0 0], [0 0], [0 0], 'm-', LineWidth=3); %[output:69c52acf]
link3 = plot3(ax, [0 0], [0 0], [0 0], 'm-', LineWidth=3); %[output:69c52acf]
hold(ax, 'on'); %[output:69c52acf]
grid(ax, 'on'); %[output:69c52acf]
grid(ax, 'minor'); %[output:69c52acf]

panel = uipanel(fig, Position=[0 0 500 200]); %[output:69c52acf]
grd = uigridlayout(panel, [4 2]); %[output:69c52acf]
grd.ColumnWidth = {20, '1x'}; %[output:69c52acf]

theta1Label = uilabel(grd); %[output:69c52acf]
theta1Label.Interpreter = 'latex'; %[output:69c52acf]
theta1Label.Text = '$\theta_1'; %[output:69c52acf]

theta1 = uislider(grd); %[output:69c52acf]
theta1.Limits = [-175 175]; %[output:69c52acf]

theta2Label = uilabel(grd); %[output:69c52acf]
theta2Label.Interpreter = 'latex'; %[output:69c52acf]
theta2Label.Text = '$\theta_2'; %[output:69c52acf]
theta2 = uislider(grd); %[output:69c52acf]
theta2.Limits = [-175 175]; %[output:69c52acf]


theta3Label = uilabel(grd); %[output:69c52acf]
theta3Label.Interpreter = 'latex'; %[output:69c52acf]
theta3Label.Text = '$\theta_3'; %[output:69c52acf]
theta3 = uislider(grd); %[output:69c52acf]
theta3.Limits = [-175 175]; %[output:69c52acf]

theta4Label = uilabel(grd); %[output:69c52acf]
theta4Label.Interpreter = 'latex'; %[output:69c52acf]
theta4Label.Text = '$\theta_4'; %[output:69c52acf]
theta4 = uislider(grd); %[output:69c52acf]
theta4.Limits = [-175 175]; %[output:69c52acf]

thetas = [theta1 theta2 theta3 theta4];

valueChanged = @() updatePlots(origin, joint2, end_effector, link2, link3, thetas);

theta1.ValueChangedFcn = @(src, event) valueChanged(); %[output:69c52acf]
theta2.ValueChangedFcn = @(src, event) valueChanged(); %[output:69c52acf]
theta3.ValueChangedFcn = @(src, event) valueChanged(); %[output:69c52acf]
theta4.ValueChangedFcn = @(src, event) valueChanged(); %[output:69c52acf]

valueChanged(); %[output:69c52acf]


function updatePlots(origin, joint2, end_effector, link2, link3, thetas)
    th1 = deg2rad(thetas(1).Value);
    th2 = deg2rad(thetas(2).Value);
    th3 = deg2rad(thetas(3).Value);
    th4 = deg2rad(thetas(4).Value);
    d = dobot(th1, th2, th3, th4);
    j2 = d.o(2);
    ee = d.o(3); % end effector

    joint2.XData = j2(1);
    joint2.YData = j2(2);
    joint2.ZData = j2(3);

    end_effector.XData = ee(1);
    end_effector.YData = ee(2);
    end_effector.ZData = ee(3);

    link2.XData = [origin.XData joint2.XData];
    link2.YData = [origin.YData joint2.YData];
    link2.ZData = [origin.ZData joint2.ZData];

    link3.XData = [joint2.XData end_effector.XData];
    link3.YData = [joint2.YData end_effector.YData];
    link3.ZData = [joint2.ZData end_effector.ZData];
end


